var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"2044년. ARC-KS1: 구 서울 역삼동\\n어느 쇼핑몰, 테러리스트 농성 중","JPN":"2044年。ARC-KS1：旧ソウル、ベルタ町\\nとあるショッピングモール、テロリストが籠城中","ENG":"2044, ARC-KS1: Former Yeoksam District, Seoul\\nTerrorist takeover in a shopping mall","TWN":"2044年 ARC-KS1: 舊首爾驛三洞\\n某購物中心，恐怖分子示威中"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"TERRORIST_NPC_GAMECIRCLE_A","text":{"KOREA":"어이, 경찰 나으리들! 잘 들리나?","JPN":"おい、警察の野郎ども！　聞こえるか？","ENG":"Yo, officers! Ya hear me?","TWN":"喂，警察大人！有聽到嗎？"},"stage":{"bg":"STORE","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TERRORIST_NPC_GAMECIRCLE_A","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L10_1","type":"dialog","speaker":"TERRORIST_NPC_GAMECIRCLE_A","text":{"KOREA":"지금부터 5분마다 여기 있는 인질들의 머리통을 하나씩 날려버리겠다!","JPN":"今から5分ごとに、ここにいる人質の頭を一人ずつ撃ち抜く！","ENG":"You see these victims? We’re gonna shoot their heads off every 5 minutes, one by one!","TWN":"現在開始，這裡每隔五分鐘就會有一個人質人頭落地！"},"stage":{"bg":"STORE","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TERRORIST_NPC_GAMECIRCLE_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"TERRORIST_NPC_GAMECIRCLE_A","text":{"KOREA":"그 꼴을 보고 싶지 않다면, 당장 여길 뜰 수 있는 헬기를 준비하라고!","JPN":"その様を見たくなけりゃ、今すぐここから脱出するヘリを用意しろ！","ENG":"If you don’t wanna bloodbath, get us our chopper now!","TWN":"要是不想有人喪命，就立刻準備一台從這裡起飛的直升機！"},"stage":{"bg":"STORE","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TERRORIST_NPC_GAMECIRCLE_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"사, 살려주세요! 전 오늘이 첫 출근이란 말이에요!","JPN":"た、助けてください！　私は今日が初出勤なんですよ！","ENG":"H-help! It's my first day at work today!","TWN":"別…別殺我！今天是我第一天上班！"},"stage":{"bg":"STORE","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"자, 잠깐! 나는 전세 대출금이 잔뜩 남아있다고! 이대로 가족들을 두고 죽을 수는 없어!","JPN":"ま、待て！　俺はまだ借金を全額返済してないんだ！　このまま家族をおいて死ぬわけにはいかない！","ENG":"W-wait! I have tons of mortgages to take care of! I can’t leave that burden on my family!","TWN":"等…等等！我還有很多房貸要繳！不能就這樣扔下家人死掉！"},"stage":{"bg":"STORE","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"저는…… 하, 학자금 대출이…….","JPN":"私は……き、教育ローンが……","ENG":"I... I have student loans...","TWN":"我…我…我還要還學貸……"},"stage":{"bg":"STORE","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"TERRORIST_NPC_GAMECIRCLE_B","text":{"KOREA":"시끄러워! 다들 여기가 무슨 대출상담소라도 되는 줄 알아!?","JPN":"うるせえ！　お前ら、ここを借金の相談窓口だとでも思ってんのか！？","ENG":"Shut up! You think this is some kind of a loan competition?!","TWN":"都給我閉嘴！你們現在把這裡當成貸款中心嗎！？"},"stage":{"bg":"STORE","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TERRORIST_NPC_GAMECIRCLE_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"TERRORIST_NPC_GAMECIRCLE_B","text":{"KOREA":"인생을 만만하게 보지 말라구! 돈이 많았으면 누가 강도질 같은 걸 하고 있겠어!","JPN":"人生なめんなよ！　俺だって金があれば強盗なんてしねえんだよ！","ENG":"You think life's easy for us, do ya?! Why do you think we're robbing this place?!","TWN":"你們以為人生有這麼容易嗎！要是有錢誰還想當搶匪！"},"stage":{"bg":"STORE","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TERRORIST_NPC_GAMECIRCLE_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"자자, 선생님들 일단 진정하시고요.","JPN":"はいはい、皆さん。とりあえず落ち着いてください。","ENG":"Now now, gentlemen. Relax.","TWN":"好好好，這位先生你先冷靜一下。"},"stage":{"bg":"STORE","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L22_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"마음이 급하신 건 알겠는데, 헬기라는 게 그렇게 영화처럼 뚝딱 준비되는 게 아니거든요.","JPN":"焦る気持ちは理解しますが、ヘリというのは映画みたいにそう簡単に用意できるものではありません。","ENG":"I understand that you are in a hurry, but it takes time for a chopper to get actually ready. It's not like in the movies, you see.","TWN":"我知道你現在很緊張，但準備直升機沒那麼簡單，電影裡面演的都是騙人的。"},"stage":{"bg":"STORE","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"헬기가 착륙할 만한 포인트도 확보해야 하고 또 그 뭐냐…… 아! 조종사를 섭외도 시간이 걸려서요. 아하하.","JPN":"ヘリが着陸するようなポイントも確保しなければならないし、あとその……あ！　操縦士の手配にも時間がかかりますので。あはは。","ENG":"We need landing points, and... what else... oh! We also need to recruit a pilot.","TWN":"首先要有直升機可以降落的停機坪，還有那個什麼……對啦！還要找到會開直升機的飛行員，這些都要花時間欸，哈哈哈。"},"stage":{"bg":"STORE","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아니면 이중에 혹시 헬기 조종 자격증이 있으신 분, 계신가요?","JPN":"それともこの中にヘリの操縦資格を持ってる方、いらっしゃいますか？","ENG":"Unless any of you is a licensed pilot... Anyone?","TWN":"還是，你們有人會開直升機嗎？"},"stage":{"bg":"STORE","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"TERRORIST_NPC_GAMECIRCLE_A","text":{"KOREA":"자, 자격증……!?","JPN":"し、資格……！？","ENG":"L-license...?!","TWN":"開…開直升機……！？"},"stage":{"bg":"STORE","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TERRORIST_NPC_GAMECIRCLE_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TERRORIST_NPC_GAMECIRCLE_B","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"TERRORIST_NPC_GAMECIRCLE_B","text":{"KOREA":"뭐야, 너! 짭새 주제에 지금 우리 형님을 무시해? 인질들이 죽어도 상관없나 보지?","JPN":"んだ、てめえ！　警察のくせに、うちの兄貴を馬鹿にしてんのか？　人質が死んでもいいのか？","ENG":"Hey, you! How dare you insult my bros! Don’t you care if these hostages die?","TWN":"你這個臭條子！現在是在耍我們大哥嗎？是不是想要我們殺人質？"},"stage":{"bg":"STORE","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TERRORIST_NPC_GAMECIRCLE_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TERRORIST_NPC_GAMECIRCLE_B","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"에이, 그럴 리가요. 이건 그런 뜻이 아니라……","JPN":"いえいえ、滅相もない。これはそういうことではなくて……","ENG":"Of course, I care. What I meant is...","TWN":"哎呀～怎麼可能，你誤會我的意思……"},"stage":{"bg":"STORE","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"엇! 호랑이도 제 말하면 온다더니, 때마침 헬기 조종사한테 연락이 왔나봐요. 잠시만요.","JPN":"あっ！　噂をすれば、ちょうどヘリの操縦士から連絡が来たみたいです。ちょっとお待ちくださいね。","ENG":"Ah, speak of the devil! It's the pilot calling. I gotta take this.","TWN":"喔！說曹操曹操到，剛好有會開直升機的飛行員打來，等我一下喔。"},"stage":{"bg":"STORE","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아하하, 경정님?","JPN":"もしもし、警視様？","ENG":"Ah ha ha, Major?","TWN":"哈哈哈，警正嗎？"},"stage":{"bg":"STORE","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L38_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"지금 어디실까요? 어째서 제가 인질 협상까지 하고 있는 걸까요?","JPN":"今どこですか？　どうして私が人質の交渉までしなきゃいけないんですか？","ENG":"And just where might you be? Would you explain why I’m filling in as the hostage negotiator?","TWN":"你現在人在哪裡？為什麼我還要在現場和歹徒談判咧？"},"stage":{"bg":"STORE","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그, 그야 어쩔 수 없잖아. 우리 측 협상 전문가가 연봉 협상에 실패해서 파업 중이라는데.","JPN":"そ、それは仕方ないでしょ？　こっちの交渉人が年俸の交渉で折り合いがつかなくてストライキ中らしいから。","ENG":"I-it can’t be helped. Our negotiator is on strike because their salary negotiation didn’t go well.","TWN":"這個…有什麼辦法，誰教我們的談判專家薪資協商失敗，現在罷工中。"},"stage":{"bg":"STORE","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"어쨌든 거의 도착했어. 상황은 어때, 강소영 경위?","JPN":"とにかくあと少しでそっちへ着くわ。状況はどう？　マエカワ警部補。","ENG":"Anyway, I’m almost there. What’s the situation down there, Lieutenant Kang?","TWN":"總之我快到了，現在情況如何，姜素英警官?"},"stage":{"bg":"STORE","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"중무장한 용의자가 셋. 관할 서의 지원이라면 제압은 어렵지 않지만 섣부르게 시도했다가 인질들이 다칠 위험이 있어요.","JPN":"重武装した容疑者が三人。管轄署の応援があれば制圧は難しくないでしょうが、下手に制圧すれば人質が怪我をする恐れがあります。","ENG":"We have three armed suspects. With backup from the local station, I presume it wouldn’t be so hard to disarm them... but there are also chances of hostage injury.","TWN":"現場有三名武裝分子，有管轄機關的支援，要壓制歹徒是沒問題，但若是貿然行動恐怕人質會有危險。"},"stage":{"bg":"STORE","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"지금이야말로, 작고 튼튼한 방탄 경정님이 나설 차례라고요.","JPN":"今こそ、体は小さくても丈夫な防弾警視様の出番ですよ。","ENG":"Now is your turn! Small and sturdy bulletproof Major.","TWN":"現在就是我們的小辣椒防彈警正出馬的時候啦～"},"stage":{"bg":"STORE","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"뭔가 비꼬는 거 같은데……?","JPN":"なんか皮肉ってない……？","ENG":"Is that sarcasm I hear...?","TWN":"怎麼覺得是在挖苦我……？"},"stage":{"bg":"STORE","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L44_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"아무튼 내가 현장에 도착할 때까지 경위가 어떻게든 시간을…….","JPN":"とにかく、私が現場に着くまで警部補がどうにかして時間を……","ENG":"Whatever it is, buy me some time until I get over th–","TWN":"總之在我抵達現場之前，你想辦法爭取時……"},"stage":{"bg":"STORE","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L46_1","type":"dialog","speaker":"TERRORIST_NPC_GAMECIRCLE_A","text":{"KOREA":"거기까지! 안타깝지만 벌써 5분이 지나버렸군.","JPN":"そこまでだ！　残念だが、もう5分過ぎちまった。","ENG":"Time’s up! Such a pity that 5 minutes go by so fast, eh?","TWN":"時間到！真是遺憾，5分鐘過去了。"},"stage":{"bg":"STORE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TERRORIST_NPC_GAMECIRCLE_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"TERRORIST_NPC_GAMECIRCLE_A","text":{"KOREA":"얘들아! 한 놈 데려와! 본때를 보여주자고!","JPN":"お前ら！　一人連れて来い！　見せしめにしてやる！","ENG":"Boys! Bring him over! Let’s teach them all a lesson!","TWN":"喂！給我帶一個人過來！我要殺雞儆猴！"},"stage":{"bg":"STORE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TERRORIST_NPC_GAMECIRCLE_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"UNCLE_NPC_GAMECIRCLE_NULL","text":{"KOREA":"……엣!?","JPN":"……えっ！？","ENG":"...Eh?!","TWN":"……我！？"},"stage":{"bg":"STORE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TERRORIST_NPC_GAMECIRCLE_B","face":"UNIT_IDLE"},"C":{"char_id":"UNCLE_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"R":{"char_id":"TERRORIST_NPC_GAMECIRCLE_C","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"TERRORIST_NPC_GAMECIRCLE_A","text":{"KOREA":"개인적인 원한은 없지만 죽어줘야겠수다, 아저씨.","JPN":"別にあんたに恨みはねえが、死んでもらうぞ。おっさん。","ENG":"No hard feelings but... your time's up, old man.","TWN":"大叔，我跟你沒有什麼私人恩怨，但你必須死。"},"stage":{"bg":"STORE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TERRORIST_NPC_GAMECIRCLE_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"UNCLE_NPC_GAMECIRCLE_NULL","text":{"KOREA":"히, 히익……!","JPN":"ひ、ひいっ……！","ENG":"E-eeek...!","TWN":"嗚，嗚嗚……！"},"stage":{"bg":"STORE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TERRORIST_NPC_GAMECIRCLE_B","face":"UNIT_IDLE"},"C":{"char_id":"UNCLE_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"R":{"char_id":"TERRORIST_NPC_GAMECIRCLE_C","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"UNCLE_NPC_GAMECIRCLE_NULL","text":{"KOREA":"자, 잠깐만요! 이러지 마세요! 저에겐 사랑하는 아내와 딸이……!","JPN":"ちょ、ちょっと！　やめてください！　私には愛する妻と娘が……！","ENG":"W-wait! Please don’t do this! I have a loving wife and daughter...!","TWN":"先…先等一下！拜託不要這樣！我還有心愛的老婆和女兒在……！"},"stage":{"bg":"STORE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TERRORIST_NPC_GAMECIRCLE_B","face":"UNIT_IDLE"},"C":{"char_id":"UNCLE_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"R":{"char_id":"TERRORIST_NPC_GAMECIRCLE_C","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"헬기는 약속대로 곧 도착할 거예요. 조용히 떠나시려면 인질은 놔두는 편이 좋을 텐데요?","JPN":"ヘリは約束通りすぐ到着します。スムーズにここから脱出したければ、人質は解放したほうが身のためですよ？","ENG":"The chopper will arrive soon, as promised. It’ll be safer to leave the hostages alone if you want to walk away.","TWN":"說好的直升機已經在路上，要是想全身而退，勸你們還是釋放人質吧？"},"stage":{"bg":"STORE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"TERRORIST_NPC_GAMECIRCLE_A","text":{"KOREA":"약속? 이제와서 무슨 소리이실까?","JPN":"約束？　今更何言ってんだ。","ENG":"Promise? I don’t know what you’re talking about.","TWN":"說好的？你在說什麼？"},"stage":{"bg":"STORE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TERRORIST_NPC_GAMECIRCLE_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"TERRORIST_NPC_GAMECIRCLE_A","text":{"KOREA":"이쪽이야말로 약속했을 텐데? 5분 당 인질 하나.","JPN":"こっちこそ約束したはずだぜ。5分ごとに人質一人殺すって。","ENG":"This is what I promised you. One hostage every 5 minutes.","TWN":"說好的應該是我每隔五分鐘就要殺一個人吧？"},"stage":{"bg":"STORE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TERRORIST_NPC_GAMECIRCLE_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"TERRORIST_NPC_GAMECIRCLE_A","text":{"KOREA":"공무원씩이나 돼서 이렇게 쉽게 약속을 잊어버리면 쓰나?","JPN":"公務員のくせに、そう簡単に約束を忘れちゃダメだろ？","ENG":"Don’t you work for the government? You shouldn’t forget promises so easily.","TWN":"吃公家飯的記性都這麼差嗎？"},"stage":{"bg":"STORE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TERRORIST_NPC_GAMECIRCLE_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"UNCLE_NPC_GAMECIRCLE_NULL","text":{"KOREA":"……다, 당신!","JPN":"……あ、あの！","ENG":"...H-hey!","TWN":"……喂…你！"},"stage":{"bg":"STORE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TERRORIST_NPC_GAMECIRCLE_B","face":"UNIT_IDLE"},"C":{"char_id":"UNCLE_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"R":{"char_id":"TERRORIST_NPC_GAMECIRCLE_C","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"TERRORIST_NPC_GAMECIRCLE_A","text":{"KOREA":"어엉?","JPN":"ああん？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"STORE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TERRORIST_NPC_GAMECIRCLE_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"UNCLE_NPC_GAMECIRCLE_NULL","text":{"KOREA":"다, 당신들에게도 가족이 있을 텐데? 이런 짓을 하면…… 가족들이……","JPN":"あ、あなたにも家族がいるでしょう。こんなことしたら……家族が……","ENG":"I-I’m sure you all have families of your own! If you do this... Your family will–","TWN":"你…你們難道沒有家人嗎？做這種事……難道不怕家人……"},"stage":{"bg":"STORE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TERRORIST_NPC_GAMECIRCLE_B","face":"UNIT_IDLE"},"C":{"char_id":"UNCLE_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"R":{"char_id":"TERRORIST_NPC_GAMECIRCLE_C","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"UNCLE_NPC_GAMECIRCLE_NULL","text":{"KOREA":"……으, 으윽!","JPN":"……う、ううっ！","ENG":"...N-ngh!","TWN":"……噢，呃呃！"},"stage":{"bg":"STORE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNCLE_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"TERRORIST_NPC_GAMECIRCLE_B","text":{"KOREA":"이 대머리 자식이 지금 겁대가리를 상실했나? 감히 형님이 말씀하시는데 끊어!?","JPN":"このハゲ野郎、今の状況が怖くねぇのか？　兄貴の話を遮るなんて！！","ENG":"This bald bastard must be out of his head! You dare cut him off when he’s talking?","TWN":"你這個禿頭大叔是吃了熊心豹子膽嗎？竟敢打斷大哥的話！？"},"stage":{"bg":"STORE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TERRORIST_NPC_GAMECIRCLE_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"TERRORIST_NPC_GAMECIRCLE_B","text":{"KOREA":"머리카락이 없으면 눈치라도 있어야지! 너 같은 자식은 더 맞아야 해!","JPN":"髪の毛がねえなら、空気くらい読めよ！　お前みたいなやつはお仕置きしてやらねぇとな！","ENG":"Gotta have wits if not hair! Baldies like you deserve to get beaten up!","TWN":"禿頭沒關係，但起碼罩子要放亮點吧！看我不揍死你！"},"stage":{"bg":"STORE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TERRORIST_NPC_GAMECIRCLE_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"TERRORIST_NPC_GAMECIRCLE_B","text":{"KOREA":"응?","JPN":"え？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"STORE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TERRORIST_NPC_GAMECIRCLE_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"TERRORIST_NPC_GAMECIRCLE_B","text":{"KOREA":"얼레? 이거 개머리판이 왜 이래? 휘었잖아!?","JPN":"は？　銃床が？　曲がっただと！？","ENG":"What happened to the stock? It’s bent!","TWN":"這是怎樣？槍把怎麼會彎掉！？"},"stage":{"bg":"STORE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TERRORIST_NPC_GAMECIRCLE_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"TERRORIST_NPC_GAMECIRCLE_C","text":{"KOREA":"너, 이 자식! 지금 무슨 개수작을 부린 거야!?","JPN":"てめえ！　今何しやがった！？","ENG":"You scumbag... What tricks are you pulling on us, huh?!","TWN":"你，你這傢伙！在給我耍什麼把戲！？"},"stage":{"bg":"STORE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TERRORIST_NPC_GAMECIRCLE_B","face":"UNIT_IDLE"},"R":{"char_id":"TERRORIST_NPC_GAMECIRCLE_C","face":"UNIT_TOUCH"}}}},{"id":"L36_1","type":"dialog","speaker":"UNCLE_NPC_GAMECIRCLE_NULL","text":{"KOREA":"쏘, 쏘지 마!! 으아아앗……!","JPN":"う、撃つな！！　うあああっ……！","ENG":"D-don’t shoot! Uahhh...!","TWN":"別…別開槍！！啊啊啊……！"},"stage":{"bg":"STORE","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNCLE_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"TERRORIST_NPC_GAMECIRCLE_C","text":{"KOREA":"으아아아악!","JPN":"うわああああ！","ENG":"Aaaagh!!","TWN":"啊啊啊啊！"},"stage":{"bg":"STORE","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_BIG"},{"id":"L42_1","type":"dialog","speaker":null,"text":{"KOREA":"바, 방금 봤어? 저 아저씨가 방금 격투게임처럼 철산고로 테러리스트를 날려버렸어!","JPN":"み、見た？　あのおじさん、さっき格ゲーみたいに鉄山靠でテロリストをぶっ飛ばした！","ENG":"D-did you see that? That guy just body checked that terrorist like they do in fighting games!","TWN":"你…你有看到嗎？剛剛那位大叔使出格鬥遊戲裡的招式鐵山靠，把恐怖分子打飛咧！"},"stage":{"bg":"STORE","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNCLE_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":null,"text":{"KOREA":"……그러고보니, 소문으로 들어 본 적 있어. 이곳 역삼동에는 살아있는 전설이 있다고.","JPN":"……そういえば、噂で聞いたことがある。このベルタ町には生ける伝説がいるって。","ENG":"...Come to think of it, I heard a rumor before. That there's a living legend here in Yeoksam.","TWN":"……這麼說來，我聽過一個八卦，說驛三洞這裡有位活傳說。"},"stage":{"bg":"STORE","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNCLE_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":null,"text":{"KOREA":"3종 침식체를 한 방에 때려잡고…… 어둠의 비밀 결사의 스카우트 제의를 거절한…… 전설적인 회사원이……!","JPN":"第3種侵食体を拳一発でやっつけて……闇の秘密結社からのスカウトを断ったという……伝説のサラリーマンが……！","ENG":"A legendary office worker who knocked out a Category 3 C.O. with a single blow... and even turned down an offer from a secret organization.","TWN":"他可以一拳打爆3類侵蝕體……還拒絕神秘黑暗組織的挖角……是傳說中的上班族……！"},"stage":{"bg":"STORE","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNCLE_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":null,"text":{"KOREA":"그, 그래? 내가 듣기로는 역삼동을 침공한 스캐빈저들의 허리를 반으로 접어서 이면세계로 날려버린 괴물 파이터라고 들었는데?","JPN":"そ、そう？　私はベルタ町に侵攻したスカベンジャーの腰を逆方向に折って、裏世界に飛ばした化け物ファイターって聞いたけど？","ENG":"R-really? I heard that when the Scavengers invaded Yeoksam, he literally crushed them in half before sending them flying back to Counterside!","TWN":"是…是喔？我聽說的是將入侵驛三洞的清道夫折成二半扔到異界的怪物欸？"},"stage":{"bg":"STORE","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNCLE_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":null,"text":{"KOREA":"저 눈빛을 봐. 당장이라도 테러리스트들의 뼈와 살을 분리수거해서 요일별로 배출시켜버릴 것 같은 눈빛이야!","JPN":"あの目つきを見てよ。今にもテロリストの骨と肉を分別して、ゴミに出してしまいそう！","ENG":"Look at his eyes. He looks as if he’s about to rip those terrorists' flesh from their bones!","TWN":"你看他的眼神，一副要將恐怖分子生吞活剝的樣子！"},"stage":{"bg":"STORE","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNCLE_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":null,"text":{"KOREA":"어쩌면…… 오늘, 우리는 이 자리에서 새로운 전설을 목격하게 될 지도 몰라!","JPN":"もしかしたら……今日、私たちはここで新しい伝説を目撃することになるかもよ！","ENG":"It’s possible... that we might witness history being written, right in front of our eyes!","TWN":"說不定……我們今天會親眼見證新的傳說！"},"stage":{"bg":"STORE","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNCLE_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":null,"text":{"KOREA":"그래! 넷튜브! 넷튜브에 올리면 조회수 100만은 우습게 넘을 거라고!","JPN":"そうだ！　ネットチューブ！　ネットチューブにアップすれば再生数100万は軽く超えるかもな！","ENG":"Oh, right! NetTube! Let's upload it on NetTube! We’ll easily surpass a million views!","TWN":"沒錯！快PO上網！肯定一下就超過百萬點閱率！"},"stage":{"bg":"STORE","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNCLE_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"TERRORIST_NPC_GAMECIRCLE_A","text":{"KOREA":"어, 어이! 자, 잠깐만! 나는 몰랐어.","JPN":"お、おい！　ちょ、ちょっと待て！　俺は知らなかったんだ。","ENG":"W-wait! Hold on! I didn't know!","TWN":"喂…喂！等…等一下！誤會一場！"},"stage":{"bg":"STORE","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNCLE_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"TERRORIST_NPC_GAMECIRCLE_A","text":{"KOREA":"아니, 몰랐습니다! 애초에 이곳이 형님의 구역인 줄 알았다면 저희는…….","JPN":"いや、知りませんでした！　ここが兄貴の縄張りだって知ってたら俺らは……","ENG":"I mean... I didn’t know, sir! If only we had known that this was your territory...","TWN":"我不知道這裡是大哥的地盤，要是早知道的話我們才……"},"stage":{"bg":"STORE","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNCLE_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"TERRORIST_NPC_GAMECIRCLE_A","text":{"KOREA":"당장 꺼지겠습니다! 그러니까 제발 모, 목숨만은……!","JPN":"今すぐ消えます！　ですからどうか、い、命だけは……！","ENG":"We will be on our way, right now! Please, spare us...!","TWN":"我們立刻滾！拜託，饒我一命……！"},"stage":{"bg":"STORE","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNCLE_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"다들 꼼짝 마! 경찰이다!","JPN":"みんな、動かないで！　警察よ！","ENG":"Freeze! Police!","TWN":"警察！不准動！"},"stage":{"bg":"STORE","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L13_1","type":"dialog","speaker":"TERRORIST_NPC_GAMECIRCLE_B","text":{"KOREA":"오, 오셨군요! 경찰 아가씨! 저 좀 살려주세요!","JPN":"よ、よくぞお越しくださいました！　警察のお嬢さん！　助けてください！","ENG":"Th-they’re here! Please, Ms. Officer! Help me!","TWN":"警察姊姊你來啦！拜託救我！"},"stage":{"bg":"STORE","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"TERRORIST_NPC_GAMECIRCLE_B","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"TERRORIST_NPC_GAMECIRCLE_A","text":{"KOREA":"너, 이 자식! 찬물에도 위아래가 있지!","JPN":"てめえ！　年功序列も知らねぇのか！","ENG":"You ungrateful scum! Don’t you know the elder comes first?!","TWN":"你這臭小子！眼裡還有我嗎！"},"stage":{"bg":"STORE","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TERRORIST_NPC_GAMECIRCLE_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TERRORIST_NPC_GAMECIRCLE_B","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"TERRORIST_NPC_GAMECIRCLE_A","text":{"KOREA":"어이! 수갑 이리 내! 빨리 날 체포하란 말이야!","JPN":"おい！　手錠をよこせ！　早く俺を逮捕してくれよ！","ENG":"Hey, you! Give me your handcuffs! Arrest me, quick!","TWN":"喂！手銬拿出來！快點逮捕我！"},"stage":{"bg":"STORE","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TERRORIST_NPC_GAMECIRCLE_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TERRORIST_NPC_GAMECIRCLE_B","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"응?","JPN":"え？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"STORE","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"쳇! 경찰인가? 조회수 100만은 물 건너 갔네.","JPN":"ちっ！　警察か？　バズる動画撮れると思ったのに。","ENG":"Tch! Cops are here? So much for our million views.","TWN":"嘖！是警察喔？百萬點閱率沒望了！"},"stage":{"bg":"STORE","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"하여간 요즘 경찰들은 낄 데, 못 낄 데를 모른다니까?","JPN":"まったく、昨今の警察はあっちこっち首突っ込みやがって。","ENG":"They just have to butt in on every situation, don’t they?","TWN":"反正警察就是礙事，每次都這樣。"},"stage":{"bg":"STORE","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"STORE","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"강소영 경위? 이게 지금 대체 무슨 상황이야?","JPN":"マエカワ警部補？　これはいったいどういう状況なの？","ENG":"Lieutenant Kang? What is going on here?","TWN":"姜素英警官？現在什麼情況？"},"stage":{"bg":"STORE","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아하하…… 글쎄요? 워낙 순식간에 일어난 일이라 저도 뭐가 뭔지……","JPN":"あはは……さあ？　あまりにも一瞬だったので、私も何が何だか……","ENG":"Ah ha ha... I have no idea. Everything happened so fast...","TWN":"哈哈哈……不知道欸？事情發生得太快我還來不及反應……"},"stage":{"bg":"STORE","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"자세한 경위는 저쪽 <color=#ffd34c>살아있는 전설</color>이라는 분에게 여쭈어보면 되지 않을까요?","JPN":"詳しい話は、あちらの<color=#ffd34c>生ける伝説</color>って人に聞いてみたらいいんじゃないですか？","ENG":"I think it’ll be best if we ask the <color=#ffd34c>living legend</color> over there. Shall we?","TWN":"來龍去脈不如問問那邊那位<color=#ffd34c>活傳說</color>吧？"},"stage":{"bg":"STORE","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"살아있는 전설? 그게 누군데?","JPN":"生ける伝説？　それって誰？","ENG":"Living legend? Who's that?","TWN":"活傳說？哪位？"},"stage":{"bg":"STORE","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"어라? 분명, 여기 계셨는데? 그새 어디 가셨지?","JPN":"あれ？　確か、ここにいたはずなんですけど。どこに行ったのかな？","ENG":"Huh? He was right there just a minute ago! Where did he go?","TWN":"嗯？剛剛明明還在這裡的？怎麼一轉眼人就不見啦？"},"stage":{"bg":"STORE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};